     }
-    if (hasKillerOpcodes(func.instructions)) {
+    if (hasKillerOpcodes(func.instructions, func.is_self_recursive)) {
         if (FREEZE_DEBUG) std.debug.print("[freeze-zig] Fast-skip '{s}': has killer opcodes\n", .{func.name});
         return null;
     }

